#!/usr/bin/env python3
"""Analyze whether the low-rank resonance fingerprint of the rwkv7-0.4b decode
activation gives SEMANTIC cache hits (paraphrases collide) vs only exact-match.

Metrics on the final pre-lm_head hidden vectors:
 (a) full-vector cosine
 (b) cosine of the RESONANCE-reduced vector = keep only top-K energy dims (K=13,50,256)
 (c) top-K energy DIM-SET Jaccard overlap
 (d) fingerprint match: sorted top-16 energy dim indices as a key; sign-of-top-dims

Report mean WITHIN-group vs mean ACROSS-group (unrelated) similarity per metric,
and whether a threshold cleanly separates paraphrases from unrelated.
"""
import json, itertools
import numpy as np

P = "/private/tmp/claude-501/-Users-buley-Documents-Code-monorepo/dab2040a-b9df-4f6b-8f0f-d96780b01544/scratchpad/resonance_acts.json"
d = json.load(open(P))
recs = d["records"]
D = d["hidden_dim"]
X = np.array([r["activation"] for r in recs], dtype=np.float64)  # (N, D)
groups = [r["group"] for r in recs]
texts = [r["text"] for r in recs]
next_tok = [r["next_token_id"] for r in recs]
N = len(recs)

def is_para_group(g):  # paraphrase groups start g*, unrelated start u_
    return g.startswith("g")

def cos(a, b):
    na, nb = np.linalg.norm(a), np.linalg.norm(b)
    if na == 0 or nb == 0: return 0.0
    return float(a @ b / (na * nb))

def topk_idx(v, k):
    e = v * v
    return set(np.argsort(e)[::-1][:k].tolist())

def reduced_cos(a, b, k):
    # keep top-k energy dims of EACH vector's own energy? Use UNION so both are
    # projected onto a common resonance support (fair for a shared cache key).
    idx = sorted(topk_idx(a, k) | topk_idx(b, k))
    return cos(a[idx], b[idx])

def jaccard(a, b, k):
    sa, sb = topk_idx(a, k), topk_idx(b, k)
    return len(sa & sb) / len(sa | sb)

# Pair partitions
within = []   # both in same paraphrase group
across = []   # not same group AND at least one is unrelated/different meaning
same_group_pairs = []
diff_pairs = []
for i, j in itertools.combinations(range(N), 2):
    same = (groups[i] == groups[j])
    if same and is_para_group(groups[i]):
        within.append((i, j))
    else:
        across.append((i, j))

def summarize(name, fn):
    w = np.array([fn(X[i], X[j]) for i, j in within])
    a = np.array([fn(X[i], X[j]) for i, j in across])
    sep = w.mean() - a.mean()
    # simple threshold quality: best split accuracy
    allv = np.concatenate([w, a])
    labels = np.concatenate([np.ones_like(w), np.zeros_like(a)])
    best_acc, best_t = 0.0, None
    for t in np.unique(allv):
        acc = ((allv >= t) == labels).mean()
        if acc > best_acc: best_acc, best_t = acc, t
    print(f"{name:32s} within={w.mean():.4f}±{w.std():.3f}  across={a.mean():.4f}±{a.std():.3f}  "
          f"sep={sep:+.4f}  bestSplitAcc={best_acc:.2f}@t={best_t:.3f}  "
          f"[within min={w.min():.3f} / across max={a.max():.3f}]")
    return w, a

print(f"N={N} prompts, D={D}, within-pairs={len(within)}, across-pairs={len(across)}\n")

print("=== (a) full-vector cosine ===")
summarize("full cosine", lambda a,b: cos(a,b))

print("\n=== (b) resonance-reduced cosine (union of top-K energy dims) ===")
for k in (13, 50, 256):
    summarize(f"reduced cosine K={k}", lambda a,b,k=k: reduced_cos(a,b,k))

print("\n=== (c) top-K energy dim-set Jaccard ===")
for k in (13, 50, 256):
    summarize(f"jaccard K={k}", lambda a,b,k=k: jaccard(a,b,k))

print("\n=== (d) fingerprint: top-16 energy dim SET Jaccard (candidate key) ===")
summarize("top16 jaccard", lambda a,b: jaccard(a,b,16))

print("\n=== (d) fingerprint: sign-of-top-K-energy-dims agreement ===")
def sign_agree(a, b, k):
    idx = sorted(topk_idx(a, k) | topk_idx(b, k))
    sa, sb = np.sign(a[idx]), np.sign(b[idx])
    return float((sa == sb).mean())
for k in (13, 50):
    summarize(f"sign-agree top-K={k}", lambda a,b,k=k: sign_agree(a,b,k))

# ---- honest caveat: is separation driven by NEXT-TOKEN prediction? -----------
print("\n=== NEXT-TOKEN caveat: do within-group pairs share the predicted next token? ===")
same_next_within = np.mean([next_tok[i]==next_tok[j] for i,j in within])
same_next_across = np.mean([next_tok[i]==next_tok[j] for i,j in across])
print(f"  share next-token: within={same_next_within:.2f}  across={same_next_across:.2f}")
# correlate cosine with same-next-token across ALL pairs
allpairs = within + across
fc = np.array([cos(X[i],X[j]) for i,j in allpairs])
sn = np.array([1.0 if next_tok[i]==next_tok[j] else 0.0 for i,j in allpairs])
print(f"  full-cosine mean when SAME next-tok={fc[sn==1].mean():.4f} (n={int(sn.sum())})  "
      f"DIFF next-tok={fc[sn==0].mean():.4f} (n={int((1-sn).sum())})")

# ---- exact-match sanity: top-16 fingerprint collisions -----------------------
print("\n=== exact fingerprint collision (identical sorted top-16 dim set)? ===")
keys = [tuple(sorted(topk_idx(X[i],16))) for i in range(N)]
coll = 0
for i,j in itertools.combinations(range(N),2):
    if keys[i]==keys[j]:
        coll += 1
        print(f"  COLLIDE: [{groups[i]}] {texts[i]!r}  ==  [{groups[j]}] {texts[j]!r}")
print(f"  total exact top-16 collisions: {coll}")

# per-group nearest neighbor by full cosine (is the nearest a same-group para?)
print("\n=== nearest-neighbor by full cosine (is NN same paraphrase group?) ===")
hits = 0; total_g = 0
for i in range(N):
    sims = [(cos(X[i],X[j]), j) for j in range(N) if j!=i]
    sims.sort(reverse=True)
    _, jbest = sims[0]
    nn_same = (groups[i]==groups[jbest]) and is_para_group(groups[i])
    if is_para_group(groups[i]):
        total_g += 1; hits += int(nn_same)
    print(f"  [{groups[i]:11s}] {texts[i][:34]:34s} -> NN [{groups[jbest]:11s}] {texts[jbest][:30]:30s} cos={sims[0][0]:.3f} {'OK' if nn_same else ''}")
print(f"  paraphrase-prompt NN-in-same-group recall: {hits}/{total_g}")
